using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace WebApi.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UploadController : ControllerBase
    {
        private readonly IWebHostEnvironment _env;

        public UploadController(IWebHostEnvironment env)
        {
            _env = env;
        }

        [HttpPost]
        public IActionResult UploadFile()
        {
            var files = Request.Form.Files;
            if (files.Count == 0) return BadRequest("No file provided");

            foreach (var file in files)
            {
                if (!IsAllowedFileType(file.FileName)) return BadRequest($"Invalid file type: {file.FileName}");

                var filePath = Path.Combine(_env.WebRootPath, "uploads", Guid.NewGuid().ToString() + "_" + file.FileName);
                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    file.CopyTo(stream);
                }
            }

            var uploadedFiles = new List<string>();
            foreach (var file in files)
            {
                uploadedFiles.Add(Path.Combine("uploads", Guid.NewGuid().ToString() + "_" + file.FileName));
            }

            return Ok(uploadedFiles);
        }

        private bool IsAllowedFileType(string fileName)
        {
            var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".pdf", ".docx", ".xlsx", ".pptx" };
            foreach (var extension in allowedExtensions)
            {
                if (fileName.EndsWith(extension, StringComparison.OrdinalIgnoreCase)) return true;
            }
            return false;
        }
    }
}